void start() {
    if (!running) {
        running = true;
        samplesUntilNextStep = 0.0;
        currentStep = 0;
        scheduledStep = 0;
    }
}

Original-Code (TypeScript):
function stop() {
  isPlaying.value = false
  if (schedulerInterval != null) {
    clearInterval(schedulerInterval)
    schedulerInterval = null
  }
  for (const timer of gateTimers.values()) clearTimeout(timer)
  gateTimers.clear()
  currentStep.value = -1
  scheduledStep = 0
}

